import React, { useState, useMemo } from 'react';

const _ = '';
const PUZZLE = [
  ['5', '3', _, _, '7', _, _, _, _],
  ['6', _, _, '1', '9', '5', _, _, _],
  [_, '9', '8', _, _, _, _, '6', _],
  ['8', _, _, _, '6', _, _, _, '3'],
  ['4', _, _, '8', _, '3', _, _, '1'],
  ['7', _, _, _, '2', _, _, _, '6'],
  [_, '6', _, _, _, _, '2', '8', _],
  [_, _, _, '4', '1', '9', _, _, '5'],
  [_, _, _, _, '8', _, _, '7', '9'],
];

function findConflicts(board) {
  const bad = new Set();
  const mark = (cells) => {
    const byDigit = {};
    for (const [r, c] of cells) {
      const v = board[r][c];
      if (!v) continue;
      (byDigit[v] = byDigit[v] || []).push(`${r},${c}`);
    }
    Object.values(byDigit).forEach((keys) => {
      if (keys.length > 1) keys.forEach((k) => bad.add(k));
    });
  };
  for (let i = 0; i < 9; i++) {
    mark(Array.from({ length: 9 }, (_, j) => [i, j])); // row
    mark(Array.from({ length: 9 }, (_, j) => [j, i])); // col
  }
  for (let br = 0; br < 9; br += 3) {
    for (let bc = 0; bc < 9; bc += 3) {
      const cells = [];
      for (let r = br; r < br + 3; r++) for (let c = bc; c < bc + 3; c++) cells.push([r, c]);
      mark(cells);
    }
  }
  return bad;
}

export default function Sudoku() {
  const [board, setBoard] = useState(PUZZLE.map((r) => [...r]));
  const given = useMemo(() => PUZZLE.map((r) => r.map((v) => v !== '')), []);
  const conflicts = useMemo(() => findConflicts(board), [board]);

  const set = (r, c, v) => {
    if (given[r][c]) return;
    if (v !== '' && !/^[1-9]$/.test(v)) return;
    setBoard((b) => b.map((row, i) => row.map((cell, j) => (i === r && j === c ? v : cell))));
  };

  return (
    <div style={{ display: 'inline-block', border: '2px solid #111', background: '#111' }}>
      {board.map((row, r) => (
        <div key={r} style={{ display: 'flex' }}>
          {row.map((cell, c) => {
            const bad = conflicts.has(`${r},${c}`);
            return (
              <input
                key={c}
                value={cell}
                onChange={(e) => set(r, c, e.target.value.slice(-1))}
                readOnly={given[r][c]}
                maxLength={1}
                style={{
                  width: 34,
                  height: 34,
                  textAlign: 'center',
                  fontSize: 18,
                  border: 'none',
                  outline: 'none',
                  background: given[r][c] ? '#e2e8f0' : '#fff',
                  color: bad ? '#dc2626' : given[r][c] ? '#111' : '#2563eb',
                  fontWeight: given[r][c] ? 700 : 400,
                  marginRight: c % 3 === 2 ? 2 : 1,
                  marginBottom: r % 3 === 2 ? 2 : 1,
                }}
              />
            );
          })}
        </div>
      ))}
    </div>
  );
}

