import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

const E = '';
const PUZZLE: string[][] = [
  ['5', '3', E, E, '7', E, E, E, E],
  ['6', E, E, '1', '9', '5', E, E, E],
  [E, '9', '8', E, E, E, E, '6', E],
  ['8', E, E, E, '6', E, E, E, '3'],
  ['4', E, E, '8', E, '3', E, E, '1'],
  ['7', E, E, E, '2', E, E, E, '6'],
  [E, '6', E, E, E, E, '2', '8', E],
  [E, E, E, '4', '1', '9', E, E, '5'],
  [E, E, E, E, '8', E, E, '7', '9'],
];

@Component({
  selector: 'app-sudoku',
  template: `
    <div style="display: inline-block; border: 2px solid #111; background: #111;">
      <div *ngFor="let row of board; let r = index" style="display: flex;">
        <input
          *ngFor="let cell of row; let c = index"
          [value]="cell"
          [readonly]="given[r][c]"
          maxlength="1"
          (input)="set(r, c, $any($event.target).value)"
          [style.background]="given[r][c] ? '#e2e8f0' : '#fff'"
          [style.color]="conflicts.has(r + ',' + c) ? '#dc2626' : (given[r][c] ? '#111' : '#2563eb')"
          [style.font-weight]="given[r][c] ? 700 : 400"
          [style.margin-right.px]="c % 3 === 2 ? 2 : 1"
          [style.margin-bottom.px]="r % 3 === 2 ? 2 : 1"
          style="width: 34px; height: 34px; text-align: center; font-size: 18px; border: none; outline: none;"
        />
      </div>
    </div>
  `,
})
export class SudokuComponent {
  board: string[][] = PUZZLE.map((r) => [...r]);
  given: boolean[][] = PUZZLE.map((r) => r.map((v) => v !== ''));

  set(r: number, c: number, v: string): void {
    if (this.given[r][c]) {
      return;
    }
    const d = v.slice(-1);
    if (d !== '' && !/^[1-9]$/.test(d)) {
      return;
    }
    this.board[r][c] = d;
  }

  get conflicts(): Set<string> {
    const bad = new Set<string>();
    const mark = (cells: number[][]) => {
      const byDigit: Record<string, string[]> = {};
      for (const [r, c] of cells) {
        const v = this.board[r][c];
        if (!v) {
          continue;
        }
        if (!byDigit[v]) {
          byDigit[v] = [];
        }
        byDigit[v].push(r + ',' + c);
      }
      Object.keys(byDigit).forEach((k) => {
        if (byDigit[k].length > 1) {
          byDigit[k].forEach((key) => bad.add(key));
        }
      });
    };
    for (let i = 0; i < 9; i++) {
      const row: number[][] = [];
      const col: number[][] = [];
      for (let j = 0; j < 9; j++) {
        row.push([i, j]);
        col.push([j, i]);
      }
      mark(row);
      mark(col);
    }
    for (let br = 0; br < 9; br += 3) {
      for (let bc = 0; bc < 9; bc += 3) {
        const cells: number[][] = [];
        for (let r = br; r < br + 3; r++) {
          for (let c = bc; c < bc + 3; c++) {
            cells.push([r, c]);
          }
        }
        mark(cells);
      }
    }
    return bad;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Sudoku Demo</h1>
      <p style="color: #666;">Fill cells 1–9. Conflicts turn red.</p>
      <app-sudoku></app-sudoku>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, SudokuComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
